package genxsolution.vms.vmsbackend.maintenance_management.maintenance_strategy.controller;
import genxsolution.vms.vmsbackend.common.query.ListQueryEngine; import genxsolution.vms.vmsbackend.maintenance_management.maintenance_strategy.dto.*; import genxsolution.vms.vmsbackend.maintenance_management.maintenance_strategy.service.MaintenanceStrategyService; import org.springframework.http.HttpStatus; import org.springframework.web.bind.annotation.*; import java.util.*;
@RestController @RequestMapping("/api/v1/vehicles/maintenance-strategies") public class MaintenanceStrategyController { private final MaintenanceStrategyService service; public MaintenanceStrategyController(MaintenanceStrategyService service){this.service=service;} @GetMapping public List<MaintenanceStrategyResponse> list(@RequestParam(required=false) UUID companyId,@RequestParam Map<String,String> filters){ return ListQueryEngine.apply(service.list(companyId), filters, Set.of("companyId")); } @GetMapping("/{id}") public MaintenanceStrategyResponse getById(@PathVariable UUID id){ return service.getById(id);} @PostMapping @ResponseStatus(HttpStatus.CREATED) public MaintenanceStrategyResponse create(@RequestBody MaintenanceStrategyUpsertRequest r){ return service.create(r);} @PutMapping("/{id}") public MaintenanceStrategyResponse update(@PathVariable UUID id,@RequestBody MaintenanceStrategyUpsertRequest r){ return service.update(id,r);} @DeleteMapping("/{id}") @ResponseStatus(HttpStatus.NO_CONTENT) public void delete(@PathVariable UUID id){ service.delete(id);} }
